// Images des passes Wallet — embarquées en base64 (le bundler edge ne suit
// pas les fichiers statiques). Sources : icône app iOS (icon 29/58/87) +
// wordmark BLANC « yuno » (Space Grotesk 700) + fond dégradé Yuno.
//
// Deux contraintes Apple pilotent ces images, ne pas les défaire :
//  - logo 160x50 .. 480x150 : c'est le PLAFOND Apple. Un wordmark qui remplit
//    le cadre rend donc au maximum absolu (l'écueil d'origine). Le cadre reste
//    160x50 pour que l'en-tête garde sa hauteur, mais le wordmark n'y occupe
//    que ~72pt de large, calé à gauche, le reste transparent.
//  - background 180x220 .. 540x660 : étiré plein cadre par Wallet, qui pose le
//    QR blanc dans le tiers bas. Le dégradé revient donc au noir en bas — sur
//    un rouge saturé, la carte blanche du QR flotte.
//
// Régénérer via : python3 scripts/gen-wallet-assets.py

function b64(data: string): Uint8Array {
  const bin = atob(data);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

